{
  "mode": "method",
  "tests": [
    {
      "name": "valid_registration",
      "input": {
        "email": "user@example.com",
        "password": "SecurePass123",
        "name": "John Doe"
      },
      "output": {
        "status": "pending",
        "message": "Registration submitted for approval."
      },
      "notes": "Tests the successful submission of a valid registration form."
    },
    {
      "name": "duplicate_registration",
      "input": {
        "email": "existing_user@example.com",
        "password": "AnotherPass123",
        "name": "Jane Doe"
      },
      "output": {
        "status": "error",
        "message": "Email already exists."
      },
      "notes": "Tests handling of a registration attempt with an existing email."
    },
    {
      "name": "empty_email",
      "input": {
        "email": "",
        "password": "SecurePass123",
        "name": "John Doe"
      },
      "output": {
        "status": "error",
        "message": "Email is required."
      },
      "notes": "Tests validation for empty email field."
    },
    {
      "name": "short_password",
      "input": {
        "email": "user@example.com",
        "password": "123",
        "name": "John Doe"
      },
      "output": {
        "status": "error",
        "message": "Password must be at least 8 characters."
      },
      "notes": "Tests validation for password length."
    },
    {
      "name": "admin_approval",
      "input": {
        "email": "user@example.com",
        "status": "approved"
      },
      "output": {
        "status": "success",
        "message": "Account approved."
      },
      "notes": "Tests the admin approval process for a registration."
    },
    {
      "name": "admin_rejection",
      "input": {
        "email": "user@example.com",
        "status": "rejected"
      },
      "output": {
        "status": "success",
        "message": "Account rejected."
      },
      "notes": "Tests the admin rejection process for a registration."
    },
    {
      "name": "invalid_email_format",
      "input": {
        "email": "invalid_email_format",
        "password": "SecurePass123",
        "name": "John Doe"
      },
      "output": {
        "status": "error",
        "message": "Invalid email format."
      },
      "notes": "Tests validation for incorrect email format."
    },
    {
      "name": "missing_fields",
      "input": {
        "email": "user@example.com",
        "password": "",
        "name": ""
      },
      "output": {
        "status": "error",
        "message": "Name and password are required."
      },
      "notes": "Tests validation for missing required fields."
    }
  ],
  "assumptions": "The backend services are functional and can handle the requests as specified.",
  "notes": "Ensure that the frontend properly communicates with the backend for registration."
}
